.darma-loader-loaders-css-18 {
      display: inline-grid;
      grid-template-columns: repeat(2, 17px);
      gap: 8px;
    }
    .darma-loader-loaders-css-18 i {
      width: 17px;
      height: 17px;
      border-radius: 4px;
      background: var(--loader-color, #f97316);
      animation: darma-loader-loaders-css-18-gridFlash 1.1400000000000001s ease-in-out infinite;
    }
    .darma-loader-loaders-css-18 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loaders-css-18 i:nth-child(2) { animation-delay: 0.08s; }
.darma-loader-loaders-css-18 i:nth-child(3) { animation-delay: 0.08s; }
.darma-loader-loaders-css-18 i:nth-child(4) { animation-delay: 0.16s; }
    @keyframes darma-loader-loaders-css-18-gridFlash { 0%, 70%, 100% { opacity: .25; transform: scale(.75); } 35% { opacity: 1; transform: scale(1); } }

